+import {Options, RuleType} from '../rules';
+import RuleBuilder, {BooleanOptionBuilder, DropdownOptionBuilder, ExampleBuilder, NumberOptionBuilder, OptionBuilderBase, TextAreaOptionBuilder, TextOptionBuilder} from './rule-builder';
+import dedent from 'ts-dedent';
+
+type ListStyle = 'bullet' | 'number';
+type OrderedListStyle = 'always-one' | 'increment';
+
+class AutoTocOptions implements Options {
+  listStyle: ListStyle = 'bullet';
+  bulletMarker: string = '-';
+  orderedListStyle: OrderedListStyle = 'always-one';
+  indentSize: Number = 2;
+  minLevel: Number = 2;
+  maxLevel: Number = 6;
+  title: string = '';
+  useExplicitIds: boolean = false;
+  stripFormattingInToc: boolean = false;
+  excludeHeadings: string[] = [];
+}
+
+type Heading = {level: number, text: string, anchor: string};
+
+const startMarker = /^\\s*<!--\\s*toc\\s*-->\\s*$/i;
+const endMarker = /^\\s*<!--\\s*\\/toc\\s*-->\\s*$/i;
+const headingPattern = /^ {0,3}(#{1,6})[ \	]+(.*?)[ \	]*$/;
+
+@RuleBuilder.register
+export default class AutoToc extends RuleBuilder<AutoTocOptions> {
+  constructor() {
+    super({
+      nameKey: 'rules.auto-toc.name',
+      descriptionKey: 'rules.auto-toc.description',
+      type: RuleType.HEADING,
+    });
+  }
+
+  get OptionsClass(): new () => AutoTocOptions {
+    return AutoTocOptions;
+  }
+
+  apply(text: string, options: AutoTocOptions): string {
+    const lineEnding = text.includes('\\r\
') ? '\\r\
' : '\
';
+    const lines = text.split(/\\r?\
/);
+    const ignoredLines = getIgnoredLines(lines);
+    const startIndex = lines.findIndex((line, index) => !ignoredLines.has(index) && startMarker.test(line));
+
+    if (startIndex === -1) {
+      return text;
+    }
+
+    const endIndex = lines.findIndex((line, index) => index > startIndex && !ignoredLines.has(index) && endMarker.test(line));
+    const tocEnd = endIndex === -1 ? startIndex : endIndex;
+    const headings = getHeadings(lines, ignoredLines, startIndex, tocEnd, options);
+    const tocLines = buildToc(headings, options);
+    const title = options.title.trim().replace(/\\r?\
/g, ' ');
+    const region = [lines[startIndex], '', ...(title ? [title, ''] : []), ...tocLines, '', endIndex === -1 ? '<!-- /toc -->' : lines[endIndex]];
+    const suffix = lines.slice(endIndex === -1 ? startIndex + 1 : endIndex + 1);
+
+    // The empty line is part of the TOC's required trailing spacing. At EOF a
+    // second empty array entry is needed so joining still leaves a blank line.
+    const result = [...lines.slice(0, startIndex), ...region, '', ...suffix];
+    if (suffix.length === 0) {
+      result.push('');
+    }
+
+    return result.join(lineEnding);
+  }
