+        before: dedent`
+          # Note
+
+          <!-- toc -->
+
+          ## First section
+          ### Second section
+        `,
+        after: dedent`
+          # Note
+
+          <!-- toc -->
+
+          - [First section](#first-section)
+            - [Second section](#second-section)
+
+          <!-- /toc -->
+
+          ## First section
+          ### Second section
+        `,
+      }),
+    ];
+  }
