+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.use-explicit-ids.name', descriptionKey: 'rules.auto-toc.use-explicit-ids.description', optionsKey: 'useExplicitIds'}),
+      new BooleanOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.strip-formatting-in-toc.name', descriptionKey: 'rules.auto-toc.strip-formatting-in-toc.description', optionsKey: 'stripFormattingInToc'}),
+      new TextAreaOptionBuilder({OptionsClass: AutoTocOptions, nameKey: 'rules.auto-toc.exclude-headings.name', descriptionKey: 'rules.auto-toc.exclude-headings.description', optionsKey: 'excludeHeadings'}),
+    ];
+  }
+}
+
+function getIgnoredLines(lines: string[]): Set<number> {
+  const ignored = new Set<number>();
+  let inYaml = lines[0]?.trim() === '---';
+  let inFence: string = null;
+  let inMath = false;
+
+  for (let index = 0; index < lines.length; index++) {
+    const line = lines[index];
+    if (inYaml) {
+      ignored.add(index);
+      if (index > 0 && /^(---|\\.\\.\\.)\\s*$/.test(line)) inYaml = false;
+      continue;
+    }
+
+    const fence = line.match(/^\\s*(`{3,}|~{3,})/);
+    if (inFence) {
+      ignored.add(index);
+      if (fence?.[1][0] === inFence && fence[1].length >= 3) inFence = null;
+      continue;
+    }
+    if (fence) {
+      ignored.add(index);
+      inFence = fence[1][0];
+      continue;
+    }
+
+    if (inMath) {
+      ignored.add(index);
+      if ((line.match(/\\$\\$/g) ?? []).length % 2 === 1) inMath = false;
+      continue;
+    }
+    if (/^\\s*\\$\\$/.test(line)) {
+      ignored.add(index);
+      if ((line.match(/\\$\\$/g) ?? []).length % 2 === 1) inMath = true;
+    }
+  }
+
+  return ignored;
+}
+
+function getHeadings(lines: string[], ignoredLines: Set<number>, tocStart: number, tocEnd: number, options: AutoTocOptions): Heading[] {
+  const minLevel = clamp(Number(options.minLevel), 1, 6);
+  const maxLevel = clamp(Number(options.maxLevel), minLevel, 6);
+  const anchors = new Map<string, number>();
+  const headings: Heading[] = [];
+
+  for (let index = 0; index < lines.length; index++) {
+    if (ignoredLines.has(index) || (index >= tocStart && index <= tocEnd)) continue;
+    const match = lines[index].match(headingPattern);
+    if (!match) continue;
+
+    const level = match[1].length;
+    const rawText = match[2].replace(/[ \	]+#+[ \	]*$/, '').trim();
+    if (level < minLevel || level > maxLevel || isExcluded(rawText, options.excludeHeadings)) continue;
+
+    const explicitId = options.useExplicitIds ? rawText.match(/\\s*\\{#([^}]+)\\}\\s*$/)?.[1] : undefined;
+    const text = rawText.replace(/\\s*\\{#[^}]+\\}\\s*$/, '').trim();
+    const baseAnchor = explicitId ?? makeAnchor(text);
+    const occurrence = anchors.get(baseAnchor) ?? 0;
+    anchors.set(baseAnchor, occurrence + 1);
+    headings.push({level, text: options.stripFormattingInToc ? stripFormatting(resolveLinks(text)) : resolveLinks(text), anchor: occurrence ? `${baseAnchor}-${occurrence}` : baseAnchor});
+  }
+
+  return headings;
+}
+
+function buildToc(headings: Heading[], options: AutoTocOptions): string[] {
+  const minLevel = clamp(Number(options.minLevel), 1, 6);
+  const indentSize = Math.max(0, Number(options.indentSize) || 0);
+  const marker = options.bulletMarker || '-';
+  let order = 0;
+  return headings.map((heading) => {
+    const indent = ' '.repeat((heading.level - minLevel) * indentSize);
+    const listMarker = options.listStyle === 'number' ? `${options.orderedListStyle === 'increment' ? ++order : 1}.` : marker;
+    return `${indent}${listMarker} [${heading.text}](#${heading.anchor})`;
+  });
+}
+
+function isExcluded(text: string, exclusions: string[]): boolean {
+  const comparableText = stripFormatting(resolveLinks(text)).toLowerCase();
+  return exclusions.some((exclusion) => {
+    const value = exclusion.trim();
+    if (value.startsWith('/') && value.endsWith('/') && value.length > 2) {
+      try {
+        return new RegExp(value.slice(1, -1), 'i').test(comparableText);
+      } catch (_) {
+        return comparableText === value.toLowerCase();
+      }
+    }
+    return comparableText === value.toLowerCase();
+  });
+}
+
+function makeAnchor(text: string): string {
+  return stripFormatting(resolveLinks(text))
+      .toLowerCase()
+      .replace(/\\s+/g, '-')
+      .replace(/[^a-z0-9_-]/g, '')
+      .replace(/-+/g, '-')
+      .replace(/^-+|-+$/g, '');
+}
+
+function resolveLinks(text: string): string {
+  return text
+      .replace(/!\\[\\[[^\\]]*\\]\\]/g, '')
+      .replace(/!\\[[^\\]]*\\]\\([^)]*\\)/g, '')
+      .replace(/\\[\\[([^\\]|]+)(?:\\|([^\\]]+))?\\]\\]/g, (_match, target: string, display: string) => display ?? target)
+      .replace(/(?<!!)\\[([^\\]]*)\\]\\([^)]*\\)/g, '$1');
+}
+
+function stripFormatting(text: string): string {
+  return text
+      .replace(/`([^`]*)`/g, '$1')
+      .replace(/(\\*\\*|__|~~|==)(.*?)\\1/g, '$2')
+      .replace(/[\\\\*]/g, '')
+      .replace(/(^|\\s)_(.*?)_(?=\\s|$)/g, '$1$2');
+}
+
+function clamp(value: number, min: number, max: number): number {
+  return Math.min(Math.max(Number.isFinite(value) ? value : min, min), max);
+}
